  1	import { useState, useEffect } from 'react';
  2	
  3	import { I18nNamespace } from '@config/config';
  4	import { useWatchedSkupperResource } from '@hooks/useSkupperWatchResource';
  5	import { Icon, Bullseye, Spinner, TextContent, Text, TextVariants, Flex, FlexItem } from '@patternfly/react-core';
  6	import { CheckCircleIcon, ExclamationCircleIcon } from '@patternfly/react-icons';
  7	import { useTranslation } from 'react-i18next';
  8	
  9	import { useLinkForm } from './hooks/useLinkForm';
 10	
 11	const WizardContentHeight = '400px';
 12	
 13	export const SummaryPage = function () {
 14	  const { t } = useTranslation(I18nNamespace);
 15	  const {
 16	    state: { name, fileName },
 17	    setIsLoading: setExternalLoading,
 18	    validated: error,
 19	    setValidated
 20	  } = useLinkForm();
 21	
 22	  const [isLoading, setIsLoading] = useState(true);
 23	
 24	  const { data: accessTokens, error: accessTokenError } = useWatchedSkupperResource({
 25	    kind: 'AccessToken',
 26	    isList: false,
 27	    name: name || fileName
 28	  });
 29	  const accessToken = accessTokens?.[0]?.rawData;
 30	
 31	  const { data: links } = useWatchedSkupperResource({ kind: 'Link', isList: false, name: name || fileName });
 32	  const link = links?.[0]?.rawData;
 33	
 34	  const hasStatus = accessToken?.status?.status || link?.status?.status;
 35	  const isConfigured = link?.status?.conditions.find(({ type, status }) => type === 'Configured' && status === 'True');
 36	  const hasError =
 37	    accessToken?.status?.status === 'Error' ||
 38	    (accessToken?.status?.status && link?.status?.status && link?.status?.status === 'Error');
 39	  const errorMessage = link?.status?.status || accessToken?.status?.message;
 40	
 41	  useEffect(() => {
 42	    if (accessTokenError) {
 43	      setIsLoading(false);
 44	      setExternalLoading(false);
 45	      setValidated('Generic error');
 46	    }
 47	
 48	    if (hasError) {
 49	      setIsLoading(false);
 50	      setExternalLoading(false);
 51	      setValidated(errorMessage);
 52	    }
 53	
 54	    if (isConfigured) {
 55	      setValidated(undefined);
 56	      setIsLoading(false);
 57	      setExternalLoading(false);
 58	
 59	      return;
 60	    }
 61	
 62	    if (!hasStatus) {
 63	      return;
 64	    }
 65	  }, [
 66	    setValidated,
 67	    setIsLoading,
 68	    setExternalLoading,
 69	    accessTokenError,
 70	    isConfigured,
 71	    hasError,
 72	    hasStatus,
 73	    errorMessage
 74	  ]);
 75	
 76	  if (isLoading) {
 77	    return (
 78	      <div style={{ height: WizardContentHeight }}>
 79	        <Bullseye>
 80	          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
 81	            <Spinner />
 82	            <p>{t('Creating link...Click Dismiss to leave the page')}</p>
 83	          </div>
 84	        </Bullseye>
 85	      </div>
 86	    );
 87	  }
 88	
 89	  if (error) {
 90	    return (
 91	      <div style={{ height: WizardContentHeight }}>
 92	        <Bullseye>
 93	          <Flex alignItems={{ default: 'alignItemsCenter' }} direction={{ default: 'column' }}>
 94	            <FlexItem>
 95	              <Icon size="xl" status="danger">
 96	                <ExclamationCircleIcon />
 97	              </Icon>
 98	            </FlexItem>
 99	
100	            <FlexItem>
101	              <TextContent style={{ textAlign: 'center' }}>
102	                <Text component={TextVariants.h2} style={{ textAlign: 'center' }}>
103	                  {t('It seems there was an error while creating the link')}
104	                </Text>
105	                <Text>{error}</Text>
106	              </TextContent>
107	            </FlexItem>
108	          </Flex>
109	        </Bullseye>
110	      </div>
111	    );
112	  }
113	
114	  return (
115	    <div style={{ height: WizardContentHeight }}>
116	      <Bullseye>
117	        <Flex alignItems={{ default: 'alignItemsCenter' }} direction={{ default: 'column' }}>
118	          <FlexItem>
119	            <Icon size="xl" status="success">
120	              <CheckCircleIcon />
121	            </Icon>
122	          </FlexItem>
123	
124	          <FlexItem>
125	            <TextContent>
126	              <Text component={TextVariants.h2} style={{ textAlign: 'center' }}>
127	                {t('Link created')}
128	              </Text>
129	              <Text>{t('Click Done to close the window')}</Text>
130	            </TextContent>
131	          </FlexItem>
132	        </Flex>
133	      </Bullseye>
134	    </div>
135	  );
136	};

